#!/usr/bin/env node
// Convert a React design system into the claude.ai/design DS-project layout.
// Two source shapes feed the same Source seam (see lib/source-*.mjs):
// storybook (.storybook/ + storybook-static) and package (dist + .d.ts,
// enriched from src/ when present). The output is identical regardless: root

input.command:
$files = Get-ChildItem "C:\Users\Niraj\.claude\projects" -Filter *.jsonl -File -ErrorAction SilentlyContinue
foreach ($f in $files) {
  $firstUser = $null
  foreach ($line in Get-Content $f.FullName) {
    try { $o = $line | ConvertFrom-Json } catch { continue }
    if ($o.type -eq 'user') {
      $c = $o.message.content
      if ($c -is [string]) { $txt = $c }
      else { $txt = ($c | Where-Object { $_.type -eq 'text' } | ForEach-Object { $_.text }) -join ' ' }
      if ($txt -and $txt -notmatch '^<command-' -and $txt.Trim().Length -gt 0) { $firstUser = $txt; break }
    }
  }
  if ($firstUser) {
    $snip = ($firstUser -replace '\s+',' ').Trim()
    if ($snip.Length -gt 200) { $snip = $snip.Substring(0,200) }
    Write-Output ("=== " + $f.Directory.Name + " | " + $f.LastWriteTime.ToString('yyyy-MM-dd HH:mm') + " ===")
    Write-Output $snip
    Write-Output ""
  }
}

$files = Get-ChildItem "C:\Users\Niraj\.claude\projects" -Filter *.jsonl -File -ErrorAction SilentlyContinue | Where-Object { $_.Directory.Name -notlike '*subagents*' -and $_.FullName -notlike '*\subagents\*' }
foreach ($f in $files) {
  $users = @()
  foreach ($line in Get-Content $f.FullName) {
    try { $o = $line | ConvertFrom-Json } catch { continue }
    if ($o.type -eq 'user') {
      $c = $o.message.content
      if ($c -is [string]) { $txt = $c }
      else { $txt = ($c | Where-Object { $_.type -eq 'text' } | ForEach-Object { $_.text }) -join ' ' }
      if ($txt -and $txt -notmatch '^<command-' -and $txt -notmatch '^\[Request interrupted' -and $txt.Trim().Length -gt 0) {
        $s = ($txt -replace '\s+',' ').Trim()
        if ($s.Length -gt 180) { $s = $s.Substring(0,180) }
        $users += $s
      }
    }
  }
  Write-Output ("##### DIR=" + $f.Directory.Name + " | FILE=" + $f.Name.Substring(0,8) + " | " + $f.LastWriteTime.ToString('yyyy-MM-dd HH:mm') + " | msgs=" + $users.Count)
  $i = 0
  foreach ($u in $users) { if ($i -ge 6) { break }; Write-Output ("  - " + $u); $i++ }
  Write-Output ""
}

$files = Get-ChildItem "C:\Users\Niraj\.claude\projects" -Filter *.jsonl -File -Recurse -ErrorAction SilentlyContinue | Where-Object { $_.FullName -notlike '*\subagents\*' }
foreach ($f in $files) {
  $users = @()
  foreach ($line in Get-Content $f.FullName) {
    try { $o = $line | ConvertFrom-Json } catch { continue }
    if ($o.type -eq 'user') {
      $c = $o.message.content
      if ($c -is [string]) { $txt = $c }
      else { $txt = ($c | Where-Object { $_.type -eq 'text' } | ForEach-Object { $_.text }) -join ' ' }
      if ($txt -and $txt -notmatch '^<command-' -and $txt -notmatch '^\[Request interrupted' -and $txt.Trim().Length -gt 0) {
        $s = ($txt -replace '\s+',' ').Trim()
        if ($s.Length -gt 220) { $s = $s.Substring(0,220) }
        $users += $s
      }
    }
  }
  Write-Output ("##### " + $f.Directory.Name + " | " + $f.LastWriteTime.ToString('yyyy-MM-dd HH:mm') + " | msgs=" + $users.Count)
  $i = 0
  foreach ($u in $users) { if ($i -ge 8) { break }; Write-Output ("  - " + $u); $i++ }
  Write-Output ""
}
